import { useState } from 'react'
import { useParams } from 'react-router-dom'
import printProducts from '../data/printProducts'

export default function ProductCustomizer() {

  const { id } = useParams()

  const product = printProducts.find(
    item => item.id === id
  )

  const presetBoxes = {

    front: {
      x: 50,
      y: 44,
      width: 430,
      height: 430
    },

    'left-chest': {
      x: 67,
      y: 29,
      width: 170,
      height: 170
    },

    back: {
      x: 50,
      y: 42,
      width: 520,
      height: 520
    }
  }

  const [selectedColor, setSelectedColor] = useState(
    product.colors[0]
  )

  const [uploadedLogo, setUploadedLogo] = useState(null)

  const [logoWidth, setLogoWidth] = useState(
    presetBoxes.front.width
  )

  const [logoHeight, setLogoHeight] = useState(
    presetBoxes.front.height
  )

  const [logoScale, setLogoScale] = useState(100)

  const [logoWarp, setLogoWarp] = useState(0)

  const [activePreset, setActivePreset] =
    useState('front')

  const [dragEnabled, setDragEnabled] =
    useState(false)

  const [customPosition, setCustomPosition] =
    useState({
      x: presetBoxes.front.x,
      y: presetBoxes.front.y
    })

  const autoFitLogo = (
    imageWidth,
    imageHeight,
    boxWidth,
    boxHeight
  ) => {

    const imageRatio =
      imageWidth / imageHeight

    const boxRatio =
      boxWidth / boxHeight

    let width
    let height

    if (imageRatio > boxRatio) {

      width = boxWidth
      height = boxWidth / imageRatio

    } else {

      height = boxHeight
      width = boxHeight * imageRatio
    }

    return {
      width,
      height
    }
  }

  const handleUpload = (e) => {

    const file = e.target.files[0]

    if (!file) return

    const imageUrl =
      URL.createObjectURL(file)

    const img = new Image()

    img.onload = () => {

      const box =
        presetBoxes[activePreset]

      const fitted =
        autoFitLogo(
          img.width,
          img.height,
          box.width,
          box.height
        )

      setLogoWidth(fitted.width)

      setLogoHeight(fitted.height)

      setLogoScale(100)

      setCustomPosition({
        x: box.x,
        y: box.y
      })

      setUploadedLogo(imageUrl)
    }

    img.src = imageUrl
  }

  const setPreset = (type) => {

    setActivePreset(type)

    const box =
      presetBoxes[type]

    setCustomPosition({
      x: box.x,
      y: box.y
    })

    if (!uploadedLogo) return

    const img = new Image()

    img.onload = () => {

      const fitted =
        autoFitLogo(
          img.width,
          img.height,
          box.width,
          box.height
        )

      setLogoWidth(fitted.width)

      setLogoHeight(fitted.height)

      setLogoScale(100)
    }

    img.src = uploadedLogo
  }

  const removeLogo = () => {

    setUploadedLogo(null)
  }

  const currentBox =
    presetBoxes[activePreset]

  return (

    <div className="h-screen bg-black text-white overflow-hidden">

      <div className="grid grid-cols-1 xl:grid-cols-[65%_35%] h-full">

        <div className="bg-[#0a0a0a] flex items-center justify-center relative overflow-hidden p-10">

          <img
            src={
              activePreset === 'back'
                ? selectedColor.backImage
                : selectedColor.image
            }
            alt="product"
            className="w-full max-w-[700px] max-h-[88vh] object-contain"
          />

          {uploadedLogo && (

            <div
              className={`absolute flex items-center justify-center overflow-hidden ${
                dragEnabled ? 'cursor-move' : ''
              }`}
              style={{
                width: `${currentBox.width}px`,
                height: `${currentBox.height}px`,
                top: `${customPosition.y}%`,
                left: `${customPosition.x}%`,
                transform:
                  'translate(-50%, -50%)'
              }}
              draggable={dragEnabled}
              onDragEnd={(e) => {

                if (!dragEnabled) return

                const rect =
                  e.currentTarget.parentElement.getBoundingClientRect()

                const x =
                  ((e.clientX - rect.left) / rect.width) * 100

                const y =
                  ((e.clientY - rect.top) / rect.height) * 100

                setCustomPosition({
                  x,
                  y
                })
              }}
            >

              <img
                src={uploadedLogo}
                alt="logo"
                className="select-none pointer-events-none"
                style={{
                  width: `${logoWidth}px`,
                  height: `${logoHeight}px`,
                  objectFit: 'contain',
                  transform: `
                    scale(${logoScale / 100})
                    perspective(900px)
                    rotateX(${logoWarp}deg)
                  `,
                  filter: `
                    contrast(1.03)
                    saturate(1.08)
                    brightness(1.02)
                  `
                }}
                draggable={false}
              />

            </div>

          )}

        </div>

        <div className="bg-black border-l border-[#1d1d1d] flex flex-col h-full overflow-y-auto">

          <div className="border-b border-[#1d1d1d] p-6">

            <p className="text-yellow-500 text-[10px] tracking-[0.3em] uppercase mb-2">
              Inspired By God
            </p>

            <h1 className="text-4xl font-black">
              {product.name}
            </h1>

          </div>

          <div className="p-6 space-y-6">

            <div>

              <button
                onClick={() =>
                  setDragEnabled(!dragEnabled)
                }
                className={`w-full py-4 rounded-xl text-xs font-black ${
                  dragEnabled
                    ? 'bg-yellow-500 text-black'
                    : 'bg-[#111] border border-[#222]'
                }`}
              >
                {dragEnabled
                  ? 'DRAG MODE ON'
                  : 'DRAG MODE OFF'}
              </button>

            </div>

          </div>

        </div>

      </div>

    </div>

  )
}
